class AdaIN(nn.Module):
    """Adaptive Instance Normalisation: y -> (scale, shift) for feature map."""
    def __init__(self, num_features: int, style_dim: int):
        super().__init__()
        self.norm = nn.InstanceNorm2d(num_features, affine=False)
        # Learn per-channel scale and shift from style vector
        self.affine = nn.Linear(style_dim, num_features * 2)

    def forward(self, x: torch.Tensor, style: torch.Tensor) -> torch.Tensor:
        # x: (B, C, H, W), style: (B, style_dim)
        x_norm = self.norm(x)                             # normalise
        gamma, beta = self.affine(style).chunk(2, dim=1)  # (B, C), (B, C)
        gamma = gamma.unsqueeze(-1).unsqueeze(-1)          # (B, C, 1, 1)
        beta = beta.unsqueeze(-1).unsqueeze(-1)
        return gamma * x_norm + beta                       # scale + shift


class AdaINBlock(nn.Module):
    """ConvTranspose2d block with AdaIN conditioning."""
    def __init__(self, in_ch: int, out_ch: int, style_dim: int):
        super().__init__()
        self.conv = nn.ConvTranspose2d(in_ch, out_ch, 4, 2, 1, bias=False)
        self.ada = AdaIN(out_ch, style_dim)
        self.act = nn.ReLU(True)

    def forward(self, x, style):
        return self.act(self.ada(self.conv(x), style))
